import type { ReactNode } from 'react';
import { NavigationMenu as NavigationMenuPrimitive } from '@base-ui/react/navigation-menu';
import { ChevronDownIcon, PopupArrowIcon } from '@/lib/moduix/icons/ui';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import styles from './NavigationMenu.module.css';

const DEFAULT_SIDE_OFFSET = 10;
const DEFAULT_COLLISION_AVOIDANCE = { side: 'none' } as const;
const DEFAULT_COLLISION_PADDING = { top: 5, bottom: 5, left: 20, right: 20 } as const;
type BasePositionerProps = NavigationMenuPrimitive.Positioner.Props;

export type NavigationMenuPositionerProps = {
  side?: BasePositionerProps['side'];
  sideOffset?: BasePositionerProps['sideOffset'];
  align?: BasePositionerProps['align'];
  alignOffset?: BasePositionerProps['alignOffset'];
  arrowPadding?: BasePositionerProps['arrowPadding'];
  anchor?: BasePositionerProps['anchor'];
  collisionAvoidance?: BasePositionerProps['collisionAvoidance'];
  collisionBoundary?: BasePositionerProps['collisionBoundary'];
  collisionPadding?: BasePositionerProps['collisionPadding'];
  sticky?: BasePositionerProps['sticky'];
  positionMethod?: BasePositionerProps['positionMethod'];
  disableAnchorTracking?: BasePositionerProps['disableAnchorTracking'];
};

export type NavigationMenuProps = NavigationMenuPrimitive.Root.Props &
  NavigationMenuPositionerProps & {
    showArrow?: boolean;
    showPopup?: boolean;
  };

export type NavigationMenuTriggerProps = NavigationMenuPrimitive.Trigger.Props & {
  icon?: ReactNode;
};

function NavigationMenu({
  className,
  children,
  showArrow = false,
  showPopup = true,
  side,
  sideOffset = DEFAULT_SIDE_OFFSET,
  align,
  alignOffset,
  arrowPadding,
  anchor,
  collisionAvoidance = DEFAULT_COLLISION_AVOIDANCE,
  collisionBoundary,
  collisionPadding = DEFAULT_COLLISION_PADDING,
  sticky,
  positionMethod,
  disableAnchorTracking,
  ...props
}: NavigationMenuProps) {
  return (
    <NavigationMenuPrimitive.Root
      data-slot="navigation-menu-root"
      className={mergeClassName(className, styles.root)}
      {...props}
    >
      {children}
      {showPopup ? (
        <NavigationMenuPortal>
          <NavigationMenuPositioner
            side={side}
            sideOffset={sideOffset}
            align={align}
            alignOffset={alignOffset}
            arrowPadding={arrowPadding}
            anchor={anchor}
            collisionAvoidance={collisionAvoidance}
            collisionBoundary={collisionBoundary}
            collisionPadding={collisionPadding}
            sticky={sticky}
            positionMethod={positionMethod}
            disableAnchorTracking={disableAnchorTracking}
          >
            <NavigationMenuPopup>
              {showArrow ? <NavigationMenuArrow /> : null}
              <NavigationMenuViewport />
            </NavigationMenuPopup>
          </NavigationMenuPositioner>
        </NavigationMenuPortal>
      ) : null}
    </NavigationMenuPrimitive.Root>
  );
}

function NavigationMenuList({ className, ...props }: NavigationMenuPrimitive.List.Props) {
  return (
    <NavigationMenuPrimitive.List
      data-slot="navigation-menu-list"
      className={mergeClassName(className, styles.list)}
      {...props}
    />
  );
}

function NavigationMenuItem(props: NavigationMenuPrimitive.Item.Props) {
  return <NavigationMenuPrimitive.Item data-slot="navigation-menu-item" {...props} />;
}

function NavigationMenuTrigger({
  className,
  children,
  icon,
  render,
  ...props
}: NavigationMenuTriggerProps) {
  return (
    <NavigationMenuPrimitive.Trigger
      data-slot="navigation-menu-trigger"
      render={render}
      className={render ? className : mergeClassName(className, styles.trigger)}
      {...props}
    >
      {children}
      {icon === null || icon === false ? null : <NavigationMenuIcon>{icon}</NavigationMenuIcon>}
    </NavigationMenuPrimitive.Trigger>
  );
}

function NavigationMenuIcon({ className, children, ...props }: NavigationMenuPrimitive.Icon.Props) {
  return (
    <NavigationMenuPrimitive.Icon
      data-slot="navigation-menu-icon"
      className={mergeClassName(className, styles.icon)}
      {...props}
    >
      {children ?? <ChevronDownIcon />}
    </NavigationMenuPrimitive.Icon>
  );
}

function NavigationMenuContent({ className, ...props }: NavigationMenuPrimitive.Content.Props) {
  return (
    <NavigationMenuPrimitive.Content
      data-slot="navigation-menu-content"
      className={mergeClassName(className, styles.content)}
      {...props}
    />
  );
}

function NavigationMenuLink({ className, ...props }: NavigationMenuPrimitive.Link.Props) {
  return (
    <NavigationMenuPrimitive.Link
      data-slot="navigation-menu-link"
      className={mergeClassName(className, styles.link)}
      {...props}
    />
  );
}

function NavigationMenuPortal({ className, ...props }: NavigationMenuPrimitive.Portal.Props) {
  return (
    <NavigationMenuPrimitive.Portal
      data-slot="navigation-menu-portal"
      className={mergeClassName(className, styles.portal)}
      {...props}
    />
  );
}

function NavigationMenuBackdrop({ className, ...props }: NavigationMenuPrimitive.Backdrop.Props) {
  return (
    <NavigationMenuPrimitive.Backdrop
      data-slot="navigation-menu-backdrop"
      className={mergeClassName(className, styles.backdrop)}
      {...props}
    />
  );
}

function NavigationMenuPositioner({
  className,
  ...props
}: NavigationMenuPrimitive.Positioner.Props) {
  return (
    <NavigationMenuPrimitive.Positioner
      data-slot="navigation-menu-positioner"
      className={mergeClassName(className, styles.positioner)}
      {...props}
    />
  );
}

function NavigationMenuPopup({ className, ...props }: NavigationMenuPrimitive.Popup.Props) {
  return (
    <NavigationMenuPrimitive.Popup
      data-slot="navigation-menu-popup"
      className={mergeClassName(className, styles.popup)}
      {...props}
    />
  );
}

function NavigationMenuArrow({
  className,
  children,
  ...props
}: NavigationMenuPrimitive.Arrow.Props) {
  return (
    <NavigationMenuPrimitive.Arrow
      data-slot="navigation-menu-arrow"
      className={mergeClassName(className, styles.arrow)}
      {...props}
    >
      {children ?? (
        <PopupArrowIcon
          fillClassName={styles.arrowFill}
          outerStrokeClassName={styles.arrowOuterStroke}
          innerStrokeClassName={styles.arrowInnerStroke}
        />
      )}
    </NavigationMenuPrimitive.Arrow>
  );
}

function NavigationMenuViewport({ className, ...props }: NavigationMenuPrimitive.Viewport.Props) {
  return (
    <NavigationMenuPrimitive.Viewport
      data-slot="navigation-menu-viewport"
      className={mergeClassName(className, styles.viewport)}
      {...props}
    />
  );
}

export {
  NavigationMenu,
  NavigationMenuList,
  NavigationMenuItem,
  NavigationMenuTrigger,
  NavigationMenuIcon,
  NavigationMenuContent,
  NavigationMenuLink,
  NavigationMenuPortal,
  NavigationMenuBackdrop,
  NavigationMenuPositioner,
  NavigationMenuPopup,
  NavigationMenuArrow,
  NavigationMenuViewport,
};

@layer ui.components {
  .root {
    box-sizing: border-box;
    min-width: var(--navigation-menu-min-width, max-content);
    padding: var(--navigation-menu-padding, var(--spacing-1));
    border-radius: var(--navigation-menu-radius, var(--radius-lg));
    background-color: var(--navigation-menu-bg, transparent);
    color: var(--navigation-menu-color, var(--color-foreground));
  }

  .list {
    position: relative;
    display: flex;
    justify-content: var(--navigation-menu-list-justify, flex-start);
    gap: var(--navigation-menu-list-gap, 0);
    margin: 0;
    padding: 0;
    list-style: none;

    .root[data-orientation='vertical'] & {
      flex-direction: column;
      align-items: stretch;
    }
  }

  .trigger,
  .link {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: flex-start;
    gap: var(--navigation-menu-trigger-gap, 0.375rem);
    min-height: var(--navigation-menu-trigger-height, var(--size-md));
    margin: 0;
    padding: var(--navigation-menu-trigger-padding-y, 0)
      var(--navigation-menu-trigger-padding-x, 0.75rem);
    border: var(--navigation-menu-trigger-border-width, 0)
      var(--navigation-menu-trigger-border-style, solid)
      var(--navigation-menu-trigger-border-color, transparent);
    border-radius: var(--navigation-menu-trigger-radius, var(--radius-md));
    background-color: var(--navigation-menu-trigger-bg, transparent);
    color: var(--navigation-menu-trigger-color, var(--color-foreground));
    font: inherit;
    font-size: var(--navigation-menu-trigger-font-size, var(--text-sm));
    line-height: var(--navigation-menu-trigger-line-height, var(--line-height-text-sm));
    text-align: left;
    text-decoration: none;
    user-select: none;
    outline: 0;
    cursor: pointer;
    transition:
      background-color var(--navigation-menu-transition, var(--transition-default)),
      color var(--navigation-menu-transition, var(--transition-default));

    @media (hover: hover) {
      &:hover {
        background-color: var(--navigation-menu-trigger-bg-hover, var(--color-accent));
      }
    }

    &:active,
    &[data-popup-open],
    &[data-active] {
      background-color: var(--navigation-menu-trigger-bg-active, var(--color-muted));
    }

    &:focus-visible {
      outline: var(--navigation-menu-focus-ring-width, var(--border-width-sm)) solid
        var(--navigation-menu-focus-ring-color, var(--color-ring));
      outline-offset: calc(var(--navigation-menu-focus-ring-width, var(--border-width-sm)) * -1);
    }

    &[data-disabled],
    &[disabled] {
      pointer-events: none;
      opacity: var(--navigation-menu-disabled-opacity, var(--opacity-disabled));
    }
  }

  .trigger {
    .root .root & {
      justify-content: flex-start;
      width: 100%;
      min-width: var(--navigation-menu-submenu-trigger-min-width, 9rem);
      text-align: left;
      background-color: var(--navigation-menu-submenu-trigger-bg, transparent);
      border-radius: var(--navigation-menu-submenu-trigger-radius, var(--radius-lg));
      padding: var(--navigation-menu-submenu-trigger-padding-y, 0.5rem)
        var(--navigation-menu-submenu-trigger-padding-x, 0.75rem);

      &:active,
      &[data-popup-open],
      &[data-active] {
        background-color: var(
          --navigation-menu-submenu-trigger-bg-active,
          var(--navigation-menu-popup-bg, var(--color-background))
        );
        box-shadow: var(
          --navigation-menu-submenu-trigger-shadow-active,
          0 1px 2px rgb(0 0 0 / 0.08),
          0 1px 1px rgb(0 0 0 / 0.04)
        );
      }
    }
  }

  .icon {
    box-sizing: border-box;
    display: inline-flex;
    width: var(--navigation-menu-icon-size, 0.875rem);
    height: var(--navigation-menu-icon-size, 0.875rem);
    flex-shrink: 0;
    color: var(--navigation-menu-icon-color, currentColor);
    transition: transform
      var(
        --navigation-menu-icon-transition,
        var(--navigation-menu-transition, var(--transition-default))
      );

    &[data-popup-open] {
      transform: rotate(180deg);
    }

    > svg {
      width: 100%;
      height: 100%;
    }

    .root .root & {
      margin-left: auto;
    }
  }

  .portal {
    z-index: var(--z-popup);
  }

  .backdrop {
    position: fixed;
    z-index: var(--z-backdrop);
    inset: 0;
    min-height: 100dvh;
    pointer-events: none;
    background-color: var(--navigation-menu-backdrop-bg, var(--backdrop-bg, var(--color-overlay)));
    backdrop-filter: var(--backdrop-filter, blur(var(--navigation-menu-backdrop-blur, 4px)));
    transition:
      opacity
        var(
          --navigation-menu-backdrop-transition,
          var(--navigation-menu-transition, var(--transition-default))
        ),
      backdrop-filter
        var(
          --navigation-menu-backdrop-transition,
          var(--navigation-menu-transition, var(--transition-default))
        );

    &[data-starting-style],
    &[data-ending-style] {
      opacity: 0;
      backdrop-filter: none;
    }
  }

  .positioner {
    --_navigation-menu-positioner-duration: var(
      --navigation-menu-popup-transition-duration,
      var(--duration-slow)
    );
    --_navigation-menu-positioner-easing: var(
      --navigation-menu-popup-transition-easing,
      var(--ease-emphasized)
    );
    box-sizing: border-box;
    z-index: var(--z-popup);
    width: var(--positioner-width);
    height: var(--positioner-height);
    max-width: min(
      var(--navigation-menu-positioner-max-width, calc(100vw - var(--spacing-8))),
      var(--available-width, 100vw)
    );
    outline: 0;
    transition:
      top var(--_navigation-menu-positioner-duration) var(--_navigation-menu-positioner-easing),
      left var(--_navigation-menu-positioner-duration) var(--_navigation-menu-positioner-easing),
      right var(--_navigation-menu-positioner-duration) var(--_navigation-menu-positioner-easing),
      bottom var(--_navigation-menu-positioner-duration) var(--_navigation-menu-positioner-easing);

    &::before {
      position: absolute;
      content: '';
    }

    &[data-side='top']::before {
      right: 0;
      bottom: calc(var(--navigation-menu-positioner-gap, 0.625rem) * -1);
      left: 0;
      height: var(--navigation-menu-positioner-gap, 0.625rem);
    }

    &[data-side='bottom']::before {
      top: calc(var(--navigation-menu-positioner-gap, 0.625rem) * -1);
      right: 0;
      left: 0;
      height: var(--navigation-menu-positioner-gap, 0.625rem);
    }

    &[data-side='left']::before,
    &[data-side='inline-start']::before {
      top: 0;
      right: calc(var(--navigation-menu-positioner-gap, 0.625rem) * -1);
      bottom: 0;
      width: var(--navigation-menu-positioner-gap, 0.625rem);
    }

    &[data-side='right']::before,
    &[data-side='inline-end']::before {
      top: 0;
      bottom: 0;
      left: calc(var(--navigation-menu-positioner-gap, 0.625rem) * -1);
      width: var(--navigation-menu-positioner-gap, 0.625rem);
    }

    &[data-instant] {
      transition: none;
    }
  }

  .popup {
    box-sizing: border-box;
    position: relative;
    width: var(--popup-width);
    height: var(--popup-height);
    border: var(--navigation-menu-popup-border-width, var(--border-width-sm))
      var(--navigation-menu-popup-border-style, solid)
      var(--navigation-menu-popup-border-color, var(--color-border));
    border-radius: var(--navigation-menu-popup-radius, var(--radius-lg));
    background-color: var(--navigation-menu-popup-bg, var(--color-popover));
    color: var(--navigation-menu-popup-color, var(--color-popover-foreground));
    box-shadow: var(--navigation-menu-popup-shadow, var(--shadow-lg));
    transform-origin: var(--transform-origin);
    transition:
      opacity var(--navigation-menu-popup-transition-duration, var(--duration-slow))
        var(--navigation-menu-popup-transition-easing, var(--ease-emphasized)),
      transform var(--navigation-menu-popup-transition-duration, var(--duration-slow))
        var(--navigation-menu-popup-transition-easing, var(--ease-emphasized)),
      width var(--navigation-menu-popup-transition-duration, var(--duration-slow))
        var(--navigation-menu-popup-transition-easing, var(--ease-emphasized)),
      height var(--navigation-menu-popup-transition-duration, var(--duration-slow))
        var(--navigation-menu-popup-transition-easing, var(--ease-emphasized));

    &[data-starting-style],
    &[data-ending-style] {
      opacity: 0;
      transform: scale(var(--navigation-menu-popup-scale, var(--scale-popup)));
    }

    &[data-ending-style] {
      transition-duration: var(--navigation-menu-popup-leave-duration, var(--duration-fast));
      transition-timing-function: var(--ease-standard);
    }
  }

  .content {
    box-sizing: border-box;
    width: min(
      var(--navigation-menu-content-width-mobile, calc(100vw - var(--spacing-8))),
      var(--available-width, 100vw)
    );
    height: 100%;
    min-width: 0;
    padding: var(--navigation-menu-content-padding, var(--spacing-4));
    overflow-wrap: anywhere;
    transition:
      opacity var(--navigation-menu-content-opacity-duration, var(--duration-normal))
        var(--ease-in-out),
      transform var(--navigation-menu-popup-transition-duration, var(--duration-slow))
        var(--navigation-menu-popup-transition-easing, var(--ease-emphasized));

    @media (min-width: 32rem) {
      width: max-content;
      min-width: var(--navigation-menu-content-min-width, 20rem);
    }

    &[data-starting-style],
    &[data-ending-style] {
      opacity: 0;
    }

    &[data-starting-style] {
      &[data-activation-direction='left'] {
        transform: translateX(calc(var(--navigation-menu-content-slide-distance, 50%) * -1));
      }

      &[data-activation-direction='right'] {
        transform: translateX(var(--navigation-menu-content-slide-distance, 50%));
      }
    }

    &[data-ending-style] {
      &[data-activation-direction='left'] {
        transform: translateX(var(--navigation-menu-content-slide-distance, 50%));
      }

      &[data-activation-direction='right'] {
        transform: translateX(calc(var(--navigation-menu-content-slide-distance, 50%) * -1));
      }
    }
  }

  .viewport {
    position: relative;
    width: 100%;
    height: 100%;
    overflow: hidden;
  }

  .arrow {
    display: flex;
    color: var(--navigation-menu-popup-bg, var(--color-popover));
    transition: left var(--navigation-menu-arrow-transition-duration, var(--duration-slow))
      var(--navigation-menu-popup-transition-easing, var(--ease-emphasized));

    &[data-side='top'] {
      bottom: calc(var(--navigation-menu-arrow-offset, 0.5rem) * -1);
      rotate: 180deg;
    }

    &[data-side='bottom'] {
      top: calc(var(--navigation-menu-arrow-offset, 0.5rem) * -1);
      rotate: 0deg;
    }

    &[data-side='left'],
    &[data-side='inline-start'] {
      right: calc(var(--navigation-menu-arrow-inline-offset, 0.8125rem) * -1);
      rotate: 90deg;
    }

    &[data-side='right'],
    &[data-side='inline-end'] {
      left: calc(var(--navigation-menu-arrow-inline-offset, 0.8125rem) * -1);
      rotate: -90deg;
    }

    & > svg {
      display: block;
      width: var(--navigation-menu-arrow-width, 1.25rem);
      height: var(--navigation-menu-arrow-height, 0.625rem);
    }
  }

  .arrowFill {
    fill: currentColor;
  }

  .arrowOuterStroke {
    fill: var(
      --navigation-menu-arrow-stroke-color,
      var(--navigation-menu-popup-border-color, var(--color-border))
    );
  }

  .arrowInnerStroke {
    fill: var(--navigation-menu-popup-bg, var(--color-popover));
  }
}

export {
  NavigationMenu,
  NavigationMenuList,
  NavigationMenuItem,
  NavigationMenuTrigger,
  NavigationMenuIcon,
  NavigationMenuContent,
  NavigationMenuLink,
  NavigationMenuPortal,
  NavigationMenuBackdrop,
  NavigationMenuPositioner,
  NavigationMenuPopup,
  NavigationMenuArrow,
  NavigationMenuViewport,
} from './NavigationMenu';

export type {
  NavigationMenuPositionerProps,
  NavigationMenuProps,
  NavigationMenuTriggerProps,
} from './NavigationMenu';
